-- Migration 16: Spiritual Growth Assessment (LifeWay-based) — 60 items, 6 disciplines.
-- Domain-bands scoring (1-5), shown as a Discipleship Wheel. Seeded unpublished;
-- publish with: update assessments set is_published=true where slug='spiritual-growth';
begin;
insert into assessments (slug,name,subtitle,category,scale_min,scale_max,estimated_minutes,questions_per_page,sensitivity,is_published)
values ('spiritual-growth','Spiritual Growth Assessment','A Discipleship Wheel Self-Assessment','personal',1,5,15,20,'standard',false)
on conflict (slug) do update set
  name=excluded.name, subtitle=excluded.subtitle, category=excluded.category,
  scale_min=excluded.scale_min, scale_max=excluded.scale_max,
  estimated_minutes=excluded.estimated_minutes, questions_per_page=excluded.questions_per_page,
  sensitivity=excluded.sensitivity;
delete from items where assessment_id=(select id from assessments where slug='spiritual-growth');
with a as (select id from assessments where slug='spiritual-growth')
insert into items (assessment_id,item_order,text,domain,is_scored,is_reverse_scored,item_type)
select a.id,v.ord,v.txt,v.dom,v.sc,v.rev,v.it::item_type from a,(values (1,'I practice a regular quiet time and look forward to that time with Christ.','Abide in Christ',true,false,'standard'),(2,'When making choices, I seek Christ''s guidance first.','Abide in Christ',true,false,'standard'),(3,'My relationship with Christ is motivated more by love than duty or fear.','Abide in Christ',true,false,'standard'),(4,'I experience life change as a result of my worship experiences.','Abide in Christ',true,false,'standard'),(5,'When God makes me aware of His specific will in an area of my life, I follow His leading.','Abide in Christ',true,false,'standard'),(6,'I believe Christ provides the only way for a relationship with God.','Abide in Christ',true,false,'standard'),(7,'My actions demonstrate a desire to build God''s kingdom rather than my own.','Abide in Christ',true,false,'standard'),(8,'Peace, contentment, and joy characterize my life rather than worry and anxiety.','Abide in Christ',true,false,'standard'),(9,'I trust Christ to help me through any problem or crisis I face.','Abide in Christ',true,false,'standard'),(10,'I remain confident of God''s love and provision during difficult times.','Abide in Christ',true,false,'standard'),(11,'I regularly read and study my Bible.','Live in the Word',true,false,'standard'),(12,'I believe the Bible is God''s Word and provides His instructions for life.','Live in the Word',true,false,'standard'),(13,'I evaluate cultural ideas and lifestyles by biblical standards.','Live in the Word',true,false,'standard'),(14,'I can answer questions about life and faith from a biblical perspective.','Live in the Word',true,false,'standard'),(15,'I replace impure or inappropriate thoughts with God''s truth.','Live in the Word',true,false,'standard'),(16,'I demonstrate honesty in my actions and conversation.','Live in the Word',true,false,'standard'),(17,'When the Bible exposes an area of my life needing change, I respond to make things right.','Live in the Word',true,false,'standard'),(18,'Generally, my public and private self are the same.','Live in the Word',true,false,'standard'),(19,'I use the Bible as the guide for the way I think and act.','Live in the Word',true,false,'standard'),(20,'I study the Bible for the purpose of discovering truth for daily living.','Live in the Word',true,false,'standard'),(21,'My prayers focus on discovering God''s will more than expressing my needs.','Pray in Faith',true,false,'standard'),(22,'I trust God to answer when I pray and wait patiently on His timing.','Pray in Faith',true,false,'standard'),(23,'My prayers include thanksgiving, praise, confession, and requests.','Pray in Faith',true,false,'standard'),(24,'I expect to grow in my prayer life and intentionally seek help to improve.','Pray in Faith',true,false,'standard'),(25,'I spend as much time listening to God as talking to Him.','Pray in Faith',true,false,'standard'),(26,'I pray because I am aware of my complete dependence on God for everything in my life.','Pray in Faith',true,false,'standard'),(27,'Regular participation in group prayer characterizes my prayer life.','Pray in Faith',true,false,'standard'),(28,'I maintain an attitude of prayer throughout each day.','Pray in Faith',true,false,'standard'),(29,'I believe my prayers impact my life and the lives of others.','Pray in Faith',true,false,'standard'),(30,'I engage in a daily prayer time.','Pray in Faith',true,false,'standard'),(31,'I forgive others when their actions harm me.','Fellowship with Believers',true,false,'standard'),(32,'I admit my errors in relationships and humbly seek forgiveness from the one I''ve hurt.','Fellowship with Believers',true,false,'standard'),(33,'I allow other Christians to hold me accountable for spiritual growth.','Fellowship with Believers',true,false,'standard'),(34,'I seek to live in harmony with other members of my family.','Fellowship with Believers',true,false,'standard'),(35,'I place the interest of others above my self-interest.','Fellowship with Believers',true,false,'standard'),(36,'I am gentle and kind in my interactions with others.','Fellowship with Believers',true,false,'standard'),(37,'I encourage and listen to feedback from others to help me discover areas for relationship growth.','Fellowship with Believers',true,false,'standard'),(38,'I show patience in my relationships with family and friends.','Fellowship with Believers',true,false,'standard'),(39,'I encourage others by pointing out their strengths rather than criticizing their weaknesses.','Fellowship with Believers',true,false,'standard'),(40,'My time commitments demonstrate that I value relationships over work/career/hobbies.','Fellowship with Believers',true,false,'standard'),(41,'I share my faith in Christ with non-believers.','Witness to the World',true,false,'standard'),(42,'I regularly pray for non-believers I know.','Witness to the World',true,false,'standard'),(43,'I make my faith known to my neighbors and/or fellow employees.','Witness to the World',true,false,'standard'),(44,'I intentionally maintain relationships with non-believers in order to share my testimony.','Witness to the World',true,false,'standard'),(45,'When confronted about my faith, I remain consistent and firm in my testimony.','Witness to the World',true,false,'standard'),(46,'I help others understand how to effectively share a personal testimony.','Witness to the World',true,false,'standard'),(47,'I make sure the people I witness to get the follow-up and support needed to grow in Christ.','Witness to the World',true,false,'standard'),(48,'I encourage my church and friends to support mission efforts.','Witness to the World',true,false,'standard'),(49,'I am prepared to share my testimony at any time.','Witness to the World',true,false,'standard'),(50,'My actions demonstrate a belief in and commitment to the Great Commission (Matthew 28:19-20).','Witness to the World',true,false,'standard'),(51,'I understand my spiritual gifts and use those gifts to serve others.','Minister to Others',true,false,'standard'),(52,'I serve others expecting nothing in return.','Minister to Others',true,false,'standard'),(53,'I sacrificially contribute my finances to help others in my church and community.','Minister to Others',true,false,'standard'),(54,'I go out of my way to show love to people I meet.','Minister to Others',true,false,'standard'),(55,'Meeting the needs of others provides a sense of purpose in my life.','Minister to Others',true,false,'standard'),(56,'I share biblical truth with those I serve as God gives opportunity.','Minister to Others',true,false,'standard'),(57,'I act as if other''s needs are as important as my own.','Minister to Others',true,false,'standard'),(58,'I expect God to use me every day in His kingdom work.','Minister to Others',true,false,'standard'),(59,'I regularly contribute time to a ministry at my church.','Minister to Others',true,false,'standard'),(60,'I help others identify ministry gifts and become involved in ministry.','Minister to Others',true,false,'standard')) as v(ord,txt,dom,sc,rev,it);
commit;
